<?php require_once __DIR__.'/../../includes/bootstrap.php'; require_login(); use app\Services\BorrowService; $svc=new BorrowService(); $errors=[]; $row=[]; if('edit'==='edit'){ $id=(int)($_GET['id']??0); $row=$svc->find($id); if(!$row) include PUBLIC_PATH.'/404.php'; } if($_SERVER['REQUEST_METHOD']==='POST'){ $_POST['created_by']=current_user()['id']; $r=('edit'==='edit')?$svc->update($id,$_POST):$svc->create($_POST); if($r['ok']){ flash('success','Đã lưu phiếu mượn'); redirect_to('borrows/index.php'); } if(!empty($r['message'])) flash('error',$r['message']); $errors=$r['errors']??[]; $row=array_merge($row,$_POST); } $title='Sửa phiếu mượn'; include ROOT_PATH.'/includes/header.php'; ?><h1 class='h3 mb-3'>Sửa phiếu mượn</h1><?php $members=(new app\Services\MemberService())->all(); $items=(new app\Services\BorrowService())->allItems(); $selectedMemberLabel=''; $selectedItemLabel=''; foreach($members as $m){ if((string)$m['id']===(string)($row['member_id']??$_POST['member_id']??'')) $selectedMemberLabel=$m['member_code'].' - '.$m['full_name'].' - '.$m['student_code']; } foreach($items as $it){ if((string)$it['id']===(string)($row['item_id']??$_POST['item_id']??'') && (string)$it['item_type']===(string)($row['item_type']??$_POST['item_type']??'')) $selectedItemLabel='['.item_type_vi($it['item_type']).'] '.$it['item_name'].' - còn '.$it['quantity']; } ?>
